from qdrant_client import QdrantClient
from qdrant_client.models import Prefetch, FusionQuery, Fusion

client = QdrantClient(path="./qdrant_db")

def qdrant_hybrid(collection_name: str, dense_query, sparse_query, limit: int = 10):
    return client.query_points(
        collection_name=collection_name,
        prefetch=[
            Prefetch(query=dense_query, using="", limit=20),
            Prefetch(query=sparse_query, using="bm25", limit=20),
        ],
        query=FusionQuery(fusion=Fusion.RRF),
        limit=limit,
    )

from elasticsearch import Elasticsearch
es = Elasticsearch(["http://localhost:9200"])

def es_hybrid(index: str, text: str, vector: list, alpha: float = 0.5, size: int = 10):
    query = {"query": {"script_score": {
        "query": {"bool": {"should": [{"match": {"content": {"query": text, "boost": 1 - alpha}}}]}},
        "script": {"source": f"{alpha} * cosineSimilarity(params.q, 'embedding') + (1-{alpha}) * _score/10",
                   "params": {"q": vector}},
    }}, "size": size}
    return es.search(index=index, body=query)["hits"]["hits"]

def determine_alpha(query: str) -> float:
    """Heuristic alpha selection based on query characteristics."""
    has_quotes = '"' in query
    has_codes = any(c.isdigit() for c in query)
    is_short = len(query.split()) <= 3
    if has_quotes:
        return 0.3   # favor keyword
    if has_codes:
        return 0.4   # lean keyword
    if is_short:
        return 0.5   # balanced
    return 0.7       # favor semantic for longer queries

from collections import defaultdict from dataclasses import dataclass from enum import Enum
class FusionMethod(Enum): RRF = "rrf" LINEAR = "linear"
@dataclass class HybridSearchConfig: alpha: float = 0.5 fusion_method: FusionMethod = FusionMethod.RRF rrf_k: int = 60
class HybridSearchService: def __init__(self, documents, embedding_service, config=None): self.documents = documents self.embedding_service = embedding_service self.config = config or HybridSearchConfig() self._build_indices()
def _build_indices(self): from rank_bm25 import BM25Okapi tokenized = [d["content"].lower().split() for d in self.documents] self.bm25 = BM25Okapi(tokenized) self.embeddings = self.embedding_service.embed_batch([d["content"] for d in self.documents])
def search(self, query: str, top_k: int = 10, alpha: float = None) -> list: alpha = alpha or self.config.alpha vec_ranking = self._vector_search(query, top_k * 2) kw_ranking = self._keyword_search(query, top_k * 2)
if self.config.fusion_method == FusionMethod.RRF: fused = self._rrf(vec_ranking, kw_ranking) else: fused = self._linear(vec_ranking, kw_ranking, alpha)
return fused[:top_k]
